import{_ as e,o as a,c as o,a3 as i}from"./chunks/framework.BveOjhN0.js";const h=JSON.parse('{"title":"Tenant API v1 — Notifications","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Tenant API v1 — Notifications | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/api/tenant-v1-notifications"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Tenant API v1 — Notifications | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/api/tenant-v1-notifications"}]]},"headers":[],"relativePath":"api/tenant-v1-notifications.md","filePath":"api/tenant-v1-notifications.md","lastUpdated":1784163688000}'),n={name:"api/tenant-v1-notifications.md"};function d(r,t,s,c,l,u){return a(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="tenant-api-v1-—-notifications" tabindex="-1">Tenant API v1 — Notifications <a class="header-anchor" href="#tenant-api-v1-—-notifications" aria-label="Permalink to &quot;Tenant API v1 — Notifications&quot;">​</a></h1><p>Base path: <code>/api/tenant/v1</code></p><p>Middleware: <code>auth:tenant-api</code>, <code>tenant.user</code>, <code>verified</code>. Authorization: <code>dashboard.view</code> (via Gate on each action).</p><p>Laravel database notifications (<code>notifications</code> table) plus mail channel on CRM notification classes. Real-time push (Reverb / Laravel Echo) is <strong>deferred</strong>; the Tenant SPA polls unread count every <strong>25 seconds</strong>.</p><h2 id="list-unread" tabindex="-1">List &amp; unread <a class="header-anchor" href="#list-unread" aria-label="Permalink to &quot;List &amp; unread&quot;">​</a></h2><h3 id="get-notifications" tabindex="-1">GET <code>/notifications</code> <a class="header-anchor" href="#get-notifications" aria-label="Permalink to &quot;GET `/notifications`&quot;">​</a></h3><p>Paginated notifications for the authenticated user.</p><p>Transformed item shape:</p><table tabindex="0"><thead><tr><th>Field</th><th>Notes</th></tr></thead><tbody><tr><td><code>id</code></td><td>UUID</td></tr><tr><td><code>type</code></td><td>Prefer <code>data.type</code> when present, else notification class</td></tr><tr><td><code>data</code></td><td>Stored payload (title, body, dedupe keys, entity refs, etc.)</td></tr><tr><td><code>read_at</code></td><td>Nullable timestamp</td></tr><tr><td><code>created_at</code></td><td></td></tr></tbody></table><h3 id="get-notifications-unread-count" tabindex="-1">GET <code>/notifications/unread-count</code> <a class="header-anchor" href="#get-notifications-unread-count" aria-label="Permalink to &quot;GET `/notifications/unread-count`&quot;">​</a></h3><p><code>{ &quot;count&quot;: number }</code></p><h2 id="mark-read" tabindex="-1">Mark read <a class="header-anchor" href="#mark-read" aria-label="Permalink to &quot;Mark read&quot;">​</a></h2><h3 id="post-notifications-id-read" tabindex="-1">POST <code>/notifications/{id}/read</code> <a class="header-anchor" href="#post-notifications-id-read" aria-label="Permalink to &quot;POST `/notifications/{id}/read`&quot;">​</a></h3><p>Marks a single notification read. 404 if not found for the current user.</p><h3 id="post-notifications-read-all" tabindex="-1">POST <code>/notifications/read-all</code> <a class="header-anchor" href="#post-notifications-read-all" aria-label="Permalink to &quot;POST `/notifications/read-all`&quot;">​</a></h3><p>Marks all unread notifications for the current user as read.</p><h2 id="channels-producers" tabindex="-1">Channels &amp; producers <a class="header-anchor" href="#channels-producers" aria-label="Permalink to &quot;Channels &amp; producers&quot;">​</a></h2><p>CRM notifications use <code>via(): [&#39;mail&#39;, &#39;database&#39;]</code>, including:</p><ul><li>Lead assigned / follow-up created / follow-up due or overdue</li><li>Task assigned / task due today or overdue</li></ul><h3 id="scheduled-due-digests" tabindex="-1">Scheduled due digests <a class="header-anchor" href="#scheduled-due-digests" aria-label="Permalink to &quot;Scheduled due digests&quot;">​</a></h3><p><code>crm:send-due-notifications</code> (hourly) walks tenants and sends idempotent due/overdue notifications for pending lead follow-ups and open tasks (deduped per day via <code>data.dedupe_key</code>).</p><h2 id="future" tabindex="-1">Future <a class="header-anchor" href="#future" aria-label="Permalink to &quot;Future&quot;">​</a></h2><ul><li>Laravel Reverb + Echo for live badge/list updates (polling remains until then)</li></ul>',23)])])}const f=e(n,[["render",d]]);export{h as __pageData,f as default};
